import React, { useState, useEffect, useRef, useCallback } from 'react';

const PAGE_SIZE = 15;
const TOTAL = 75;

// Fake paged API.
function fetchPage(page) {
  return new Promise((resolve) => {
    setTimeout(() => {
      const start = page * PAGE_SIZE;
      const items = Array.from({ length: Math.min(PAGE_SIZE, TOTAL - start) }, (_, i) => start + i + 1);
      resolve({ items, hasMore: start + PAGE_SIZE < TOTAL });
    }, 600);
  });
}

export default function InfiniteScroll() {
  const [items, setItems] = useState([]);
  const [page, setPage] = useState(0);
  const [loading, setLoading] = useState(false);
  const [done, setDone] = useState(false);
  const sentinel = useRef(null);

  const loadMore = useCallback(async () => {
    if (loading || done) return;
    setLoading(true);
    const next = await fetchPage(page);
    setItems((prev) => [...prev, ...next.items]);
    setDone(!next.hasMore);
    setPage((p) => p + 1);
    setLoading(false);
  }, [page, loading, done]);

  useEffect(() => {
    const node = sentinel.current;
    if (!node) return;
    const io = new IntersectionObserver((entries) => {
      if (entries[0].isIntersecting) loadMore();
    });
    io.observe(node);
    return () => io.disconnect();
  }, [loadMore]);

  return (
    <div style={{ height: 320, overflowY: 'auto', border: '1px solid #ddd', borderRadius: 8, padding: 12, maxWidth: 360 }}>
      <ul style={{ listStyle: 'none', margin: 0, padding: 0 }}>
        {items.map((n) => (
          <li key={n} style={{ padding: '10px 12px', marginBottom: 8, background: '#f3f4f6', borderRadius: 6 }}>
            Item #{n}
          </li>
        ))}
      </ul>
      {loading && <p style={{ textAlign: 'center', color: '#888' }}>Loading…</p>}
      {done && <p style={{ textAlign: 'center', color: '#aaa' }}>— end —</p>}
      <div ref={sentinel} style={{ height: 1 }} />
    </div>
  );
}

