import { Component, ViewChild, ElementRef, AfterViewInit, OnDestroy } from '@angular/core';
import { NgModule } from '@angular/core';
import { BrowserModule } from '@angular/platform-browser';

const PAGE_SIZE = 15;
const TOTAL = 75;

@Component({
  selector: 'app-infinite-scroll',
  template: `
    <div style="height: 320px; overflow-y: auto; border: 1px solid #ddd; border-radius: 8px; padding: 12px; max-width: 360px;">
      <ul style="list-style: none; margin: 0; padding: 0;">
        <li *ngFor="let n of items" style="padding: 10px 12px; margin-bottom: 8px; background: #f3f4f6; border-radius: 6px;">Item #{{ n }}</li>
      </ul>
      <p *ngIf="loading" style="text-align: center; color: #888;">Loading…</p>
      <p *ngIf="done" style="text-align: center; color: #aaa;">— end —</p>
      <div #sentinel style="height: 1px;"></div>
    </div>
  `,
})
export class InfiniteScrollComponent implements AfterViewInit, OnDestroy {
  items: number[] = [];
  page = 0;
  loading = false;
  done = false;
  private io: IntersectionObserver | null = null;

  @ViewChild('sentinel') sentinel!: ElementRef<HTMLElement>;

  fetchPage(page: number): Promise<{ items: number[]; hasMore: boolean }> {
    return new Promise((resolve) => {
      setTimeout(() => {
        const start = page * PAGE_SIZE;
        const items: number[] = [];
        for (let i = 0; i < Math.min(PAGE_SIZE, TOTAL - start); i++) {
          items.push(start + i + 1);
        }
        resolve({ items, hasMore: start + PAGE_SIZE < TOTAL });
      }, 600);
    });
  }

  async loadMore(): Promise<void> {
    if (this.loading || this.done) {
      return;
    }
    this.loading = true;
    const next = await this.fetchPage(this.page);
    this.items = [...this.items, ...next.items];
    this.done = !next.hasMore;
    this.page++;
    this.loading = false;
  }

  ngAfterViewInit(): void {
    this.io = new IntersectionObserver((entries) => {
      if (entries[0].isIntersecting) {
        this.loadMore();
      }
    });
    this.io.observe(this.sentinel.nativeElement);
  }

  ngOnDestroy(): void {
    if (this.io) {
      this.io.disconnect();
    }
  }
}

@Component({
  selector: 'app-root',
  template: `
    <div style="font-family: sans-serif; padding: 20px;">
      <h1>Infinite Scroll Demo</h1>
      <app-infinite-scroll></app-infinite-scroll>
    </div>
  `,
})
export class AppComponent {}

@NgModule({
  declarations: [AppComponent, InfiniteScrollComponent],
  imports: [BrowserModule],
  bootstrap: [AppComponent],
})
export class AppModule {}
